// ===== modes.js =====

// ---------- 模式选择 ----------
function selectMode(mode) {
    document.getElementById('mode-select-panel').style.display='none';
    if(mode==='raise') {
        S.lobsterMode='raise';
        initState();
        showWelcomeLobster();
        document.getElementById('welcome-panel').classList.add('show');
        document.getElementById('btn-start').disabled=false;
    } else if(mode==='import') {
        S.lobsterMode='import';
        initState();
        document.getElementById('import-panel').classList.add('show');
        document.getElementById('import-code').value='';
        document.getElementById('import-error').style.display='none';
        document.getElementById('btn-start').disabled=false;
    }
    updateUI();
}

function restartGame() {
    document.getElementById('game-over').classList.remove('show','lose','win');
    document.getElementById('battle-log').innerHTML='';
    initState();
    showWelcomeLobster();
    document.getElementById('btn-start').disabled=false;
    document.getElementById('welcome-panel').classList.add('show');
    updateUI();
}

function closeWelcome() {
    document.getElementById('welcome-panel').classList.remove('show');
    document.getElementById('btn-start').disabled=false;
}

// ---------- 成虾导入/导出 ----------
function confirmImport() {
    const code=document.getElementById('import-code').value.trim();
    if(!code) return;
    const imported=importLobster(code);
    if(!imported) {
        document.getElementById('import-error').style.display='block';
        return;
    }
    document.getElementById('import-panel').classList.remove('show');
    document.getElementById('welcome-panel').classList.remove('show');
    addLog('<span class="log-system">🦐 成虾 【'+imported.name+'】 导入成功!</span>');
    // 显示成虾模式选择面板
    showLobsterModePanel();
    updateUI();
}

function showLobsterModePanel() {
    const p=S.player;
    const sprite=PHASE_SPRITES[p.phase]||'🦐';
    const desc='等级: Lv.'+p.level+' | 阶别: '+PHASES[p.phase]+' | 技能: '+p.skills.length+'个';
    document.getElementById('lobster-mode-desc').innerHTML=sprite+'<br>'+p.name+'<br><small style="color:#aaa">'+desc+'</small>';
    document.getElementById('lobster-mode-panel').classList.add('show');
}

function closeLobsterModePanel() {
    document.getElementById('lobster-mode-panel').classList.remove('show');
    document.getElementById('mode-select-panel').style.display='flex';
}

function selectLobsterMode(mode) {
    document.getElementById('lobster-mode-panel').classList.remove('show');
    if(mode==='endless') {
        S.lobsterMode='endless';
        S.round=1;
        // 成虾不成长：禁止升级、禁止偷技能
        S.noGrowth=true;
        S.noSkillSteal=true;
        addLog('<span class="log-system">♾️ 进入无尽模式！怪物难度从第6轮开始...</span>');
        document.getElementById('btn-start').disabled=false;
    } else if(mode==='pvp') {
        S.lobsterMode='pvp';
        // PVP模式：显示对手导入面板
        document.getElementById('pvp-import-panel').classList.add('show');
        document.getElementById('pvp-import-code').value='';
        document.getElementById('pvp-import-error').style.display='none';
    }
    updateUI();
}

function closePvpImportPanel() {
    document.getElementById('pvp-import-panel').classList.remove('show');
    document.getElementById('lobster-mode-panel').classList.add('show');
}

function confirmPvpImport() {
    const code=document.getElementById('pvp-import-code').value.trim();
    if(!code) return;
    const opponent=parseLobsterCode(code);
    if(!opponent) {
        document.getElementById('pvp-import-error').style.display='block';
        document.getElementById('pvp-import-error').textContent='对手代码无效，请重新输入';
        return;
    }
    // 保存对手数据
    S.pvpOpponent=JSON.parse(JSON.stringify({
        name:opponent.name, level:opponent.level, phase:opponent.phase,
        hp:opponent.hp, maxHp:opponent.maxHp,
        atk:opponent.atk, def:opponent.def, spd:opponent.spd,
        skills:opponent.skills,
        buffs:[], shields:0, poisonDmg:0, bleedDmg:0, alive:true,
        resurrected:false, resurrectedUsed:false,
        stunned:false, sealed:false,
        speedBoosted:false, defReduced:false,
        resurrectRate:0, counterRate:0, reduceDmgRate:0, lifesteal:0
    }));
    // 传递被动技能属性
    S.pvpOpponent.skills.forEach(s=>{
        if(s.passive){
            if(s.id==='lifesteal') S.pvpOpponent.lifesteal=s.lifesteal;
            if(s.id==='counter') S.pvpOpponent.counterRate=s.counterRate;
            if(s.id==='resurrect') S.pvpOpponent.resurrectRate=s.resurrectRate;
            if(s.id==='speedBoost'||s.id==='overclock') S.pvpOpponent.speedBoosted=true;
        }
    });
    document.getElementById('pvp-import-panel').classList.remove('show');
    S.pvpReady=true;
    addLog('<span class="log-system">⚔️ 对手 【'+opponent.name+'】 已就位!</span>');
    document.getElementById('btn-start').disabled=false;
    updateUI();
}

function importLobster(code) {
    try {
        const lobster=parseLobsterCode(code);
        if(!lobster) return null;
        S.player=lobster;
        S.phase=lobster.phase;
        return S.player;
    } catch(e) {
        return null;
    }
}

function exportLobster() {
    const p=S.player;
    const data=[
        1, p.name, p.level, p.phase, Math.floor(p.hp),
        p.baseHp, p.baseAtk, p.baseDef, p.baseSpd,
        p.skills.map(s=>ALL_SKILLS.findIndex(x=>x.id===s.id)).filter(i=>i>=0)
    ];
    const bytes=new TextEncoder().encode(JSON.stringify(data));
    let binary='';
    for(let i=0;i<bytes.length;i++) binary+=String.fromCharCode(bytes[i]);
    return btoa(binary).replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
}

function parseLobsterCode(code) {
    const data=JSON.parse(decodeLobsterCode(code));
    if(!Array.isArray(data)||data[0]!==1||!Array.isArray(data[9])) return null;
    const skills=data[9].map(i=>ALL_SKILLS[i]).filter(Boolean).map(cloneSkill);
    if(!data[2]||data[3]===undefined||skills.length===0) return null;
    const lobster={
        name:data[1]||'龙虾',
        level:data[2], phase:data[3],
        hp:data[4]||1, maxHp:1, atk:1, def:1, spd:1,
        skills,
        buffs:[], shields:0, poisonDmg:0, bleedDmg:0, alive:true,
        resurrected:false, resurrectedUsed:false,
        stunned:false, sealed:false,
        speedBoosted:false, defReduced:false,
        resurrectRate:0, counterRate:0, reduceDmgRate:0, lifesteal:0,
        vulnerable:0, armorBroken:0, regenLeft:0,
        dodgeRate:0, reflectRate:0, reflectDmg:0, shieldBoostRate:0, regenRate:0,
        baseHp:data[5]||100, baseAtk:data[6]||10,
        baseDef:data[7]||4, baseSpd:data[8]||6,
        hpM:1, atkM:1
    };
    if(typeof refreshPassiveSkills==='function') refreshPassiveSkills(lobster);
    calcEntityStats(lobster);
    return lobster;
}

function decodeLobsterCode(code) {
    const clean=code.replace(/\s/g,'').replace(/-/g,'+').replace(/_/g,'/');
    const padded=clean+'='.repeat((4-clean.length%4)%4);
    return new TextDecoder().decode(new Uint8Array(atob(padded).split('').map(c=>c.charCodeAt(0))));
}

function closeImportPanel() {
    document.getElementById('import-panel').classList.remove('show');
    document.getElementById('mode-select-panel').style.display='flex';
}
function closeExportPanel() {
    document.getElementById('export-panel').classList.remove('show');
    document.getElementById('btn-start').disabled=true;
    addLog('<span class="log-system">🦐 养虾完成！请复制成虾代码保存，或重新开始新游戏。</span>');
}
function showExportPanel() {
    const code=exportLobster();
    document.getElementById('export-code').value=code;
    document.getElementById('reward-panel').style.display='none';
    document.getElementById('export-panel').classList.add('show');
}
function copyExportCode() {
    const code=document.getElementById('export-code').value;
    navigator.clipboard.writeText(code).then(()=>{
        addLog('<span class="log-system">📋 成虾代码已复制到剪贴板!</span>');
    }).catch(()=>{
        document.getElementById('export-code').select();
        document.execCommand('copy');
        addLog('<span class="log-system">📋 成虾代码已复制到剪贴板!</span>');
    });
}
function showWelcomeLobster() {
    if(!S.player||!S.player.skills) return;
    const p=S.player;
    const sprite=PHASE_SPRITES[p.phase]||'🦐';
    const stats='生命:'+p.maxHp+' 攻:'+p.atk+' 防:'+p.def+' 速:'+p.spd;
    document.getElementById('welcome-sprite').textContent=sprite;
    document.getElementById('welcome-name').textContent=p.name+' (Lv.'+p.level+') '+PHASES[p.phase];
    document.getElementById('welcome-stats').textContent=stats;
    document.getElementById('welcome-skills').textContent='技能: '+p.skills.map(s=>s.icon+s.name).join(' ');
}
